+ 		}
+ 		if (cp[0] == '0'){
+ 		    cp++;
+@@ -6232,6 +6232,7 @@
+ 	    while ('0'<= *cp && *cp <='9') {
+ 		alpha_f |= 1 << (*cp++ - '0');
+ 	    }
++	    if (alpha_f & ((1 << 2) | (1 << 3))) alpha_f |= 1;
+ 	    if (!alpha_f) alpha_f = 1;
+ 	    continue;
+ 	case 'x':   /* Convert X0201 kana to X0208 or X0201 Conversion */
+diff -urBbN nkf-2.0.9/nkf_test.pl nkf.cur/nkf_test.pl
