++print "SJIS to UTF-16LE-BOM...";&test("$nkf --oc=UTF-16LE-BOM",h("82A0"),h("FFFE4230"));
++print "SJIS to -w32...        ";&test("$nkf -w32",h("82A0"),h("0000FEFF00003042"));
++print "SJIS to UTF-32...      ";&test("$nkf --oc=UTF-32",h("82A0"),h
